//! Tier-C breadth: user-defined helper calls, template/member IR, and the
//! v2 envelope — tested against the CHECKED-IN extracted topologies of the
//! source-borne `echo.ts` benchmark (provenance + regen discipline as in
//! `walker_parity.rs`).
//!
//! Expected values are gnexec's observed outputs (verified 2026-07-03):
//!   gnexec echo.ts --export app --input-json '{"name":"x"}' → hello:x
//!   gnexec echo.ts --export app --input-json '{}'           → hello:null
//!     (the walker TRAPS on the missing field instead — decline, not
//!     divergence; templates are string-only in this version)

use gg_walker_wasm::{
    run_envelope_bytes, run_program, run_topology, validate_program, Helpers, Topology,
};
use serde_json::{json, Value};

fn fixture(name: &str) -> String {
    let path = format!("{}/tests/fixtures/{name}", env!("CARGO_MANIFEST_DIR"));
    std::fs::read_to_string(&path).unwrap_or_else(|e| panic!("read {path}: {e}"))
}

fn app() -> Topology {
    serde_json::from_str(&fixture("echo.ts.app.topology.json")).expect("app fixture parses")
}

fn greet_helpers() -> Helpers {
    let mut helpers = Helpers::new();
    helpers.insert(
        "greet".to_string(),
        serde_json::from_str(&fixture("echo.ts.greet.topology.json"))
            .expect("greet fixture parses"),
    );
    helpers
}

#[test]
fn echo_ts_app_matches_gnexec() {
    let out = run_program(&app(), &greet_helpers(), &json!({"name": "x"})).expect("app walks");
    assert_eq!(out, Value::String("hello:x".into()));

    let out = run_program(&app(), &greet_helpers(), &json!({"name": "ada"})).expect("app walks");
    assert_eq!(out, Value::String("hello:ada".into()));
}

#[test]
fn echo_ts_program_validates_statically() {
    validate_program(&app(), &greet_helpers()).expect("echo.ts program admits");
}

#[test]
fn v2_envelope_round_trip() {
    let envelope = format!(
        r#"{{"topology":{},"helpers":{{"greet":{}}},"input":{{"name":"x"}}}}"#,
        fixture("echo.ts.app.topology.json"),
        fixture("echo.ts.greet.topology.json"),
    );
    let out = run_envelope_bytes(envelope.as_bytes()).expect("v2 envelope runs");
    assert_eq!(out, r#""hello:x""#);
}

// ── Fail-closed (decline) cases ──────────────────────────────────────

#[test]
fn missing_input_field_declines() {
    // gnexec answers "hello:null" here; the walker refuses to coerce.
    let err = run_program(&app(), &greet_helpers(), &json!({})).unwrap_err();
    assert!(err.0.contains("no field"), "{err}");
}

#[test]
fn non_string_template_ref_declines() {
    // gnexec would stringify the number; string-only templates trap instead.
    let err = run_program(&app(), &greet_helpers(), &json!({"name": 5})).unwrap_err();
    assert!(err.0.contains("non-string"), "{err}");
}

#[test]
fn unknown_callee_without_helper_declines() {
    // The same topology run WITHOUT its helper (v1 semantics) must decline
    // at load — `greet` has no certified builtin and no helper topology.
    let err = run_topology(&app(), &json!({"name": "x"})).unwrap_err();
    assert!(err.0.contains("greet"), "{err}");
}

#[test]
fn arity_mismatch_declines() {
    let mut topology = app();
    for node in &mut topology.nodes {
        if node.properties.get("callee").map(String::as_str) == Some("greet") {
            node.properties.insert(
                "args".to_string(),
                r#"[{"kind":"literal","value":"a"},{"kind":"literal","value":"b"}]"#.to_string(),
            );
        }
    }
    let err = validate_program(&topology, &greet_helpers()).unwrap_err();
    assert!(err.0.contains("takes"), "{err}");
    assert!(run_program(&topology, &greet_helpers(), &json!({"name": "x"})).is_err());
}

#[test]
fn uncertified_arg_ir_declines() {
    let mut topology = app();
    for node in &mut topology.nodes {
        if node.properties.get("callee").map(String::as_str) == Some("greet") {
            node.properties.insert(
                "args".to_string(),
                r#"[{"kind":"binary","op":"+","lhs":{"kind":"literal","value":1},"rhs":{"kind":"literal","value":2}}]"#
                    .to_string(),
            );
        }
    }
    let err = validate_program(&topology, &greet_helpers()).unwrap_err();
    assert!(err.0.contains("binary"), "{err}");
}

#[test]
fn recursive_helper_declines() {
    // A helper whose body calls itself: statically acyclic admission must
    // refuse it (and run_program re-validates, so it traps at run time too).
    let recursive: Topology = serde_json::from_str(
        r#"{"nodes":[
             {"id":"e","labels":["Entry"],"properties":{"param_names":"[\"n\"]"}},
             {"id":"s","labels":["Statement","PolyglotBridgeCall"],
              "properties":{"callee":"loop","bind":"v","args":"[{\"kind\":\"ident\",\"name\":\"n\"}]"}},
             {"id":"r","labels":["Return"],"properties":{"expr":"{\"kind\":\"ident\",\"name\":\"v\"}"}}],
           "edges":[
             {"source_ids":["e"],"target_ids":["s"],"type":"Process","properties":{}},
             {"source_ids":["s"],"target_ids":["r"],"type":"Process","properties":{}}]}"#,
    )
    .expect("recursive helper parses");
    let mut helpers = Helpers::new();
    helpers.insert("loop".to_string(), recursive.clone());

    let err = validate_program(&recursive, &helpers).unwrap_err();
    assert!(err.0.contains("recursi"), "{err}");
    assert!(run_program(&recursive, &helpers, &json!("x")).is_err());
}

#[test]
fn invalid_unused_helper_declines() {
    // Every helper in the envelope must admit, reached or not — fail closed.
    let mut helpers = greet_helpers();
    helpers.insert(
        "junk".to_string(),
        serde_json::from_str(
            r#"{"nodes":[{"id":"m","labels":["MysteryNode"],"properties":{}}],"edges":[]}"#,
        )
        .expect("junk parses"),
    );
    let err = validate_program(&app(), &helpers).unwrap_err();
    assert!(err.0.contains("junk"), "{err}");
}

#[test]
fn reserved_helper_name_declines() {
    let mut helpers = greet_helpers();
    let greet = helpers["greet"].clone();
    helpers.insert("merge".to_string(), greet);
    let err = validate_program(&app(), &helpers).unwrap_err();
    assert!(err.0.contains("merge"), "{err}");
}

#[test]
fn helpers_cannot_see_root_input() {
    // Inside a helper frame the legacy `input.<field>` string form resolves
    // against null — helpers see only their bound parameters.
    let helper: Topology = serde_json::from_str(
        r#"{"nodes":[
             {"id":"e","labels":["Entry"],"properties":{"param_names":"[\"x\"]"}},
             {"id":"r","labels":["Return"],"properties":{"expr":"input.name"}}],
           "edges":[
             {"source_ids":["e"],"target_ids":["r"],"type":"Process","properties":{}}]}"#,
    )
    .expect("helper parses");
    let root: Topology = serde_json::from_str(
        r#"{"nodes":[
             {"id":"e","labels":["Entry"],"properties":{"param_names":"[\"input\"]"}},
             {"id":"s","labels":["Statement","PolyglotBridgeCall"],
              "properties":{"callee":"peek","bind":"v","args":"[{\"kind\":\"literal\",\"value\":\"a\"}]"}},
             {"id":"r","labels":["Return"],"properties":{"expr":"{\"kind\":\"ident\",\"name\":\"v\"}"}}],
           "edges":[
             {"source_ids":["e"],"target_ids":["s"],"type":"Process","properties":{}},
             {"source_ids":["s"],"target_ids":["r"],"type":"Process","properties":{}}]}"#,
    )
    .expect("root parses");
    let mut helpers = Helpers::new();
    helpers.insert("peek".to_string(), helper);
    let err = run_program(&root, &helpers, &json!({"name": "secret"})).unwrap_err();
    assert!(err.0.contains("no field"), "{err}");
}

/// Width-1 foil forks certify: the mesh scheduler (x-gnosis
/// mesh-schedule.ts) splits an N-arm Promise.all into N width-1 arm
/// sub-topologies, each walked on its own station; the coordinator's
/// "|" fold of the arm results must equal the full-topology walk. This
/// test pins the arm-level contract: a single-branch fork answers with
/// that branch's result alone.
#[test]
fn width_one_foil_fork_certifies_and_answers() {
    let full: serde_json::Value = serde_json::from_str(include_str!(
        "fixtures/fanout.gg.topology.json"
    ))
    .expect("fixture parses");

    // Narrow the fixture to the loadProfile arm the way the mesh
    // coordinator does: drop the other branch, rewrite the width
    // consistency properties (branches/arity/branch_index) to 1/0.
    let mut arm = full.clone();
    {
        let nodes = arm["nodes"].as_array_mut().expect("nodes");
        nodes.retain(|node| node["id"] != "foil_branch_5");
        for node in nodes.iter_mut() {
            let id = node["id"].as_str().unwrap_or_default().to_string();
            let props = node["properties"].as_object_mut().expect("props");
            if id == "statement_1" {
                props.insert("branches".into(), "1".into());
            } else if id == "foil_join_4" {
                props.insert("arity".into(), "1".into());
            } else if id == "foil_branch_6" {
                props.insert("branch_index".into(), "0".into());
            }
        }
        let edges = arm["edges"].as_array_mut().expect("edges");
        for edge in edges.iter_mut() {
            if edge["type"] == "Fork" {
                edge["target_ids"] = serde_json::json!(["foil_branch_6"]);
            } else if edge["type"] == "Fold" {
                edge["source_ids"] = serde_json::json!(["foil_branch_6"]);
            }
        }
    }

    let envelope = serde_json::json!({
        "topology": arm,
        "input": {"userId": "ada"}
    });
    let out = gg_walker_wasm::run_envelope_bytes(
        serde_json::to_string(&envelope).expect("serialize").as_bytes(),
    )
    .expect("width-1 arm walks");
    assert_eq!(out, "\"ada:profile\"");

    // Zero-width forks stay declined.
    let mut zero = full;
    for node in zero["nodes"].as_array_mut().expect("nodes").iter_mut() {
        if node["id"] == "statement_1" {
            node["properties"]
                .as_object_mut()
                .expect("props")
                .remove("branches");
        }
    }
    for edge in zero["edges"].as_array_mut().expect("edges").iter_mut() {
        if edge["type"] == "Fork" {
            edge["target_ids"] = serde_json::json!([]);
        }
    }
    let zero_envelope = serde_json::json!({
        "topology": zero,
        "input": {"userId": "ada"}
    });
    let err = gg_walker_wasm::run_envelope_bytes(
        serde_json::to_string(&zero_envelope).expect("serialize").as_bytes(),
    )
    .expect_err("zero-width fork declines");
    // The decline may fire at graph build (empty edge endpoints) or at
    // the fork recognizer (>= 1 branch target) — either way, zero-width
    // stays fail-closed.
    assert!(err.to_string().contains("gg-walker decline"));
}
